interface MenuItemFormProps {
  restaurantId: string;
  onSuccess?: () => void;
}

export default function MenuItemForm({ restaurantId, onSuccess }: MenuItemFormProps) {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [price, setPrice] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const response = await fetch('/api/menu-items', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name, description, price: parseFloat(price), restaurantId }),
    });

    if (response.ok) {
      setName('');
      setDescription('');
      setPrice('');
      onSuccess?.();
    }
  };

  return (
